import { useIntl } from 'react-intl';

import {
  ArrowSmallLeftIcon,
  ArrowSmallRightIcon,
} from '@dynatrace/strato-icons';

import { PANNING_CONTROLS_MESSAGES } from './messages.js';
import { panningArrow, panningButtons } from './PanningControls.sty.js';
import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';

const PANNING_STEP = 40;

interface PanningControlsProps {
  showRightControl: boolean;
  showLeftControl: boolean;
  onClickPan: (domain: number) => void;
}

export const PanningControls = (props: PanningControlsProps) => {
  const { showRightControl, showLeftControl, onClickPan } = props;

  const intl = useIntl();

  return (
    <>
      {showLeftControl && (
        <button
          aria-label={intl.formatMessage(
            PANNING_CONTROLS_MESSAGES.buttonLeftLabel,
          )}
          className={panningButtons({ direction: 'toLeft' })}
          onClick={() => onClickPan(PANNING_STEP)}
        >
          <Tooltip
            text={intl.formatMessage(PANNING_CONTROLS_MESSAGES.panLeft)}
            placement="bottom"
          >
            <ArrowSmallLeftIcon size="default" className={panningArrow} />
          </Tooltip>
        </button>
      )}

      {showRightControl && (
        <button
          aria-label={intl.formatMessage(
            PANNING_CONTROLS_MESSAGES.buttonRightLabel,
          )}
          className={panningButtons({ direction: 'toRight' })}
          onClick={() => onClickPan(-PANNING_STEP)}
        >
          <Tooltip
            text={intl.formatMessage(PANNING_CONTROLS_MESSAGES.panRight)}
            placement="bottom"
          >
            <ArrowSmallRightIcon size="default" className={panningArrow} />
          </Tooltip>
        </button>
      )}
    </>
  );
};
